import{_ as o,o as d,c,a6 as a}from"./chunks/framework.CgU7tkAh.js";const D=JSON.parse('{"title":"Database","description":"","frontmatter":{},"headers":[],"relativePath":"config/api/database.md","filePath":"config/api/database.md"}'),i={name:"config/api/database.md"};function l(t,e,n,_,s,r){return d(),c("div",null,[...e[0]||(e[0]=[a('<h1 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to “Database”">​</a></h1><p>Path: <code>packages/db/src/config.ts</code></p><p>Connection info is defined per-environment and per-database.</p><p>System consists of two databases:</p><ul><li><code>Foods</code> - food-related information, mostly static content</li><li><code>System</code> - users / surveys related information, system configuration etc</li></ul><p><strong>Environments</strong>:</p><ul><li><code>development</code> - local development environment</li><li><code>test</code> - local tests and CI environment</li><li><code>production</code> - production environment</li></ul><p><strong>Connection types</strong></p><ol><li>Connection URL - use <code>url</code> property</li><li>Connection credentials - use <code>host</code>, <code>port</code>, <code>database</code>, <code>username</code> and <code>password</code> properties</li></ol><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to “URL”">​</a></h2><p>Examples</p><p><code>DB_DEV_SYSTEM_URL=postgres://intake24:intake24@localhost:5432/intake24_system_dev</code></p><p><code>DB_DEV_FOODS_URL=postgres://intake24:intake24@localhost:5432/intake24_foods_dev</code></p><ul><li>object-path: <code>[environment][database].url</code></li><li>dotenv vars: <ul><li><code>development</code>: <code>DB_DEV_FOODS_URL</code> and <code>DB_DEV_SYSTEM_URL</code></li><li><code>test</code>: <code>DB_TEST_FOODS_URL</code> and <code>DB_TEST_SYSTEM_URL</code></li><li><code>production</code>: <code>DB_FOODS_URL</code> and <code>DB_SYSTEM_URL</code></li></ul></li><li>type: <code>string | undefined</code></li><li>default: <code>undefined</code></li></ul><h2 id="host" tabindex="-1">Host <a class="header-anchor" href="#host" aria-label="Permalink to “Host”">​</a></h2><ul><li>object-path: <code>[environment][database].host</code></li><li>dotenv vars: <ul><li><code>development</code>: <code>DB_DEV_FOODS_HOST</code> and <code>DB_DEV_SYSTEM_HOST</code></li><li><code>test</code>: <code>DB_TEST_FOODS_HOST</code> and <code>DB_TEST_SYSTEM_HOST</code></li><li><code>production</code>: <code>DB_FOODS_HOST</code> and <code>DB_SYSTEM_HOST</code></li></ul></li><li>type: <code>string | undefined</code></li><li>default: <code>undefined</code></li></ul><h2 id="port" tabindex="-1">Port <a class="header-anchor" href="#port" aria-label="Permalink to “Port”">​</a></h2><ul><li>object-path: <code>[environment][database].port</code></li><li>dotenv vars: <ul><li><code>development</code>: <code>DB_DEV_FOODS_PORT</code> and <code>DB_DEV_SYSTEM_PORT</code></li><li><code>test</code>: <code>DB_TEST_FOODS_PORT</code> and <code>DB_TEST_SYSTEM_PORT</code></li><li><code>production</code>: <code>DB_FOODS_PORT</code> and <code>DB_SYSTEM_PORT</code></li></ul></li><li>type: <code>number | undefined</code></li><li>default: <code>undefined</code></li></ul><h2 id="database-1" tabindex="-1">Database <a class="header-anchor" href="#database-1" aria-label="Permalink to “Database”">​</a></h2><ul><li>object-path: <code>[environment][database].database</code></li><li>dotenv vars: <ul><li><code>development</code>: <code>DB_DEV_FOODS_DATABASE</code> and <code>DB_DEV_SYSTEM_DATABASE</code></li><li><code>test</code>: <code>DB_TEST_FOODS_DATABASE</code> and <code>DB_TEST_SYSTEM_DATABASE</code></li><li><code>production</code>: <code>DB_FOODS_DATABASE</code> and <code>DB_SYSTEM_DATABASE</code></li></ul></li><li>type: <code>string | undefined</code></li><li>default: <code>undefined</code></li></ul><h2 id="username" tabindex="-1">Username <a class="header-anchor" href="#username" aria-label="Permalink to “Username”">​</a></h2><ul><li>object-path: <code>[environment][database].username</code></li><li>dotenv vars: <ul><li><code>development</code>: <code>DB_DEV_FOODS_USERNAME</code> and <code>DB_DEV_SYSTEM_USERNAME</code></li><li><code>test</code>: <code>DB_TEST_FOODS_USERNAME</code> and <code>DB_TEST_SYSTEM_USERNAME</code></li><li><code>production</code>: <code>DB_FOODS_USERNAME</code> and <code>DB_SYSTEM_USERNAME</code></li></ul></li><li>type: <code>string | undefined</code></li><li>default: <code>undefined</code></li></ul><h2 id="password" tabindex="-1">Password <a class="header-anchor" href="#password" aria-label="Permalink to “Password”">​</a></h2><ul><li>object-path: <code>[environment][database].password</code></li><li>dotenv vars: <ul><li><code>development</code>: <code>DB_DEV_FOODS_PASSWORD</code> and <code>DB_DEV_SYSTEM_PASSWORD</code></li><li><code>test</code>: <code>DB_TEST_FOODS_PASSWORD</code> and <code>DB_TEST_SYSTEM_PASSWORD</code></li><li><code>production</code>: <code>DB_FOODS_PASSWORD</code> and <code>DB_SYSTEM_PASSWORD</code></li></ul></li><li>type: <code>string | undefined</code></li><li>default: <code>undefined</code></li></ul><h2 id="pool-max-connections" tabindex="-1">Pool max connections <a class="header-anchor" href="#pool-max-connections" aria-label="Permalink to “Pool max connections”">​</a></h2><ul><li>object-path: <code>[environment][database].pool.max</code></li><li>dotenv vars: <ul><li><code>development</code>: <code>DB_DEV_FOODS_POOL_MAX</code> and <code>DB_DEV_SYSTEM_POOL_MAX</code></li><li><code>test</code>: <code>DB_TEST_FOODS_POOL_MAX</code> and <code>DB_TEST_SYSTEM_POOL_MAX</code></li><li><code>production</code>: <code>DB_FOODS_POOL_MAX</code> and <code>DB_SYSTEM_POOL_MAX</code></li></ul></li><li>type: <code>number</code></li><li>default: <code>10</code></li></ul><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to “Security”">​</a></h2><p>SSL connection for database (only Postgresql dialect supported at the moment)</p><ul><li>object-path: <code>[environment].security</code></li><li>dotenv vars: <ul><li><code>development</code>: <code>DB_DEV_FOODS_SSL</code> and <code>DB_DEV_SYSTEM_SSL</code></li><li><code>test</code>: <code>DB_TEST_FOODS_SSL</code> and <code>DB_TEST_SYSTEM_SSL</code></li><li><code>production</code>: <code>DB_FOODS_SSL</code> and <code>DB_SYSTEM_SSL</code></li></ul></li><li>type: <code>&#39;true&#39; | &#39;false&#39;</code></li><li>default: <code>&#39;false&#39;</code></li></ul>',29)])])}const u=o(i,[["render",l]]);export{D as __pageData,u as default};
